module top_module(
	input [7:0] dataIn,
	output [7:0] dataOut
);reg [7:0] obf_data;
  always @ (dataIn) begin     
    case(dataIn)
      8'h1D    : obf_data = 8'd87;     
      8'h1B    : obf_data = 8'd83;
		8'h1C    : obf_data = 8'd65;
		8'h23    : obf_data = 8'd68;
      default  : obf_data = 0;     
    endcase
  end

  assign dataOut = obf_data;

endmodule
